export function setCityTranslations(locale: Locale, data: CityTranslationMap): void {
  translations[locale] = data;
}

export function getCityTranslations(locale: Locale): CityTranslationMap {
  return translations[locale] ?? {};
}

function applyCityTranslation(city: City, t: CityTranslationOverlay | undefined): City {
  if (!t) return city;
  return {
    ...city,
    subtitle: t.subtitle ?? city.subtitle,
    description: t.description ?? city.description,
    longDescription: t.longDescription ?? city.longDescription,
    badge: t.badge ?? city.badge,
    highlights: t.highlights ?? city.highlights,
    suitableFor: t.suitableFor ?? city.suitableFor,
    notSuitableFor: t.notSuitableFor ?? city.notSuitableFor,
    faq: t.faq ?? city.faq,
  };
}

export function getCities(locale: Locale): City[] {
  const overlay = getCityTranslations(locale);
  return baseCities.map((c) => applyCityTranslation(c, overlay[c.slug]));
}

export function getCityBySlug(slug: string, locale: Locale): City | undefined {
  const overlay = getCityTranslations(locale);
  const base = baseCities.find((c) => c.slug === slug);
  if (!base) return undefined;
  return applyCityTranslation(base, overlay[slug]);
}

export function getFeaturedCities(locale: Locale): City[] {
  const overlay = getCityTranslations(locale);
  return baseGetFeatured().map((c) => applyCityTranslation(c, overlay[c.slug]));
}

export function getCitiesByCategory(category: string, locale: Locale): City[] {
  const overlay = getCityTranslations(locale);
  return baseGetByCategory(category).map((c) => applyCityTranslation(c, overlay[c.slug]));
}

export function getCityServiceMatchNames(locale: Locale, slugs: string[]): { slug: string; name: string }[] {
  return slugs.map((slug) => {
    const city = baseCities.find((c) => c.slug === slug);
    return { slug, name: city?.name ?? slug };
  });
}
